local function check_permissions()
    local token = ngx.req.get_headers()["Authorization"]
    if not token then
        ngx.status = 401
        ngx.say("Unauthorized")
        ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Validate token (example implementation)
    if token ~= "valid_token" then
        ngx.status = 403
        ngx.say("Forbidden")
        ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    local user_role = "user" -- Example role, should be fetched from token or database
    local allowed_roles = {"admin", "editor"}

    if not table.contains(allowed_roles, user_role) then
        ngx.status = 403
        ngx.say("Forbidden")
        ngx.exit(ngx.HTTP_FORBIDDEN)
    end
end

local function table.contains(tbl, value)
    for _, v in ipairs(tbl) do
        if v == value then
            return true
        end
    end
    return false
end

if not ngx.var.uri:find("/admin") and not ngx.var.uri:find("/api") then
    check_permissions()
end